32	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (100 + 30 + 5 = 135 G)");
33	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (105 G)");
34	  it.todo("sword enchant 5 and cursed → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
35	  it.todo("long-standing customer (exactly 2 years) → 20% loyalty discount applies");
36	  it.todo("first insurance surcharge (10%) applies to each item in a quote");
37	
38	  // ---------- Multi-item modifier scope (❓ per-item vs policy-wide) ----------
39	  it.todo("policy with cursed sword + plain amulet → 210 G before fee = 215 G total (curse applies only to cursed item)");
40	
41	  // ---------- Rounding in MHPCO's favor ----------
42	  it.todo("premium yielding 197.5 G → 198 G (rounded up)");
43	  it.todo("payout yielding 350.5 G → 350 G (rounded down)");
