51	  it.todo("rune damage 200 G → payout 100 G (no special clause: 200 − 100 deductible)");
52	
53	  // ---------- Special clauses ----------
54	  it.todo("steel sword, enchant 9, damage 1000 G → payout 400 G (high-enchantment 50% then deductible)");
55	  it.todo("dragon-material sword, enchant 5, damage 800 G → payout 700 G (dragon: full, then deductible)");
56	  it.todo("dragon-material sword, enchant 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
57	  it.todo("dragon-material sword, enchant exactly 8, damage 1000 G → payout 400 G (high-enchantment wins)");
58	
59	  // ---------- Deductible per damage event ----------
